import 'package:flutter/foundation.dart';

enum PaymentMethod { applePay, googlePay, creditCard, inAppPurchase }

enum TransactionStatus { pending, processing, completed, failed, refunded, cancelled }

enum SubscriptionPeriod { weekly, monthly, quarterly, yearly }

class PaymentResult {
  final bool success;
  final String? transactionId;
  final String? errorMessage;
  final TransactionStatus status;
  final double amount;
  final String currency;
  final DateTime timestamp;
  final Map<String, dynamic>? metadata;

  PaymentResult({
    required this.success,
    this.transactionId,
    this.errorMessage,
    required this.status,
    required this.amount,
    this.currency = 'USD',
    DateTime? timestamp,
    this.metadata,
  }) : timestamp = timestamp ?? DateTime.now();

  Map<String, dynamic> toJson() => {
        'success': success,
        'transactionId': transactionId,
        'errorMessage': errorMessage,
        'status': status.name,
        'amount': amount,
        'currency': currency,
        'timestamp': timestamp.toIso8601String(),
        'metadata': metadata,
      };

  factory PaymentResult.failure(String error) => PaymentResult(
        success: false,
        errorMessage: error,
        status: TransactionStatus.failed,
        amount: 0,
      );

  factory PaymentResult.fromJson(Map<String, dynamic> json) => PaymentResult(
        success: json['success'] as bool,
        transactionId: json['transactionId'] as String?,
        errorMessage: json['errorMessage'] as String?,
        status: TransactionStatus.values.firstWhere(
          (e) => e.name == json['status'],
          orElse: () => TransactionStatus.failed,
        ),
        amount: (json['amount'] as num).toDouble(),
        currency: json['currency'] as String? ?? 'USD',
        timestamp: DateTime.parse(json['timestamp'] as String),
        metadata: json['metadata'] as Map<String, dynamic>?,
      );
}

