class DeviceSecurityService {
  static DeviceSecurityService? _instance;
  final LocalAuthentication _localAuth = const LocalAuthentication() as LocalAuthentication;
  final FlutterSecureStorage _secureStorage = const FlutterSecureStorage();

  DeviceSecurityService._();

  static DeviceSecurityService get instance {
    _instance ??= DeviceSecurityService._();
    return _instance!;
  }

  Future<DeviceSecurityStatus> performSecurityCheck() async {
    final results = await Future.wait([
      _checkRootStatus(),
      _checkEmulatorStatus(),
      _checkBiometricAvailability(),
      _performIntegrityCheck(),
    ]);

    return DeviceSecurityStatus(
      isRooted: results[0] as bool,
      isEmulator: results[1] as bool,
      hasSecureScreen: true,
      biometricAvailable: results[2] as bool,
      integrityCheckPassed: results[3] as bool,
      checkedAt: DateTime.now(),
    );
  }

  Future<bool> _checkRootStatus() async {
    try {
      return await FlutterJailbreakDetection.jailbroken;
    } catch (e) {
      return true; // Assume compromised if check fails
    }
  }

  Future<bool> _checkEmulatorStatus() async {
    try {
      if (Platform.isAndroid) {
        return await _detectAndroidEmulator();
      } else if (Platform.isIOS) {
        return await _detectIOSSimulator();
      }
      return false;
    } catch (e) {
      return true;
    }
  }

  Future<bool> _detectAndroidEmulator() async {
    try {
      const platform = MethodChannel('com.payment.security/device');
      final result = await platform.invokeMethod<bool>('isEmulator');
      return result ?? true;
    } catch (e) {
      // Fallback heuristic checks
      final checks = <bool>[
        Platform.environment.containsKey('ANDROID_EMULATOR'),
      ];
      return checks.any((check) => check);
    }
  }

  Future<bool> _detectIOSSimulator() async {
    try {
      const platform = MethodChannel('com.payment.security/device');
      final result = await platform.invokeMethod<bool>('isSimulator');
      return result ?? true;
    } catch (e) {
      return false;
    }
  }

  Future<bool> _checkBiometricAvailability() async {
    try {
      final canAuthenticate = await _localAuth.canCheckBiometrics;
      final isDeviceSupported = await _localAuth.isDeviceSupported();
      return canAuthenticate && isDeviceSupported;
    } catch (e) {
      return false;
    }
  }

  Future<bool> authenticateUser(String reason) async {
    try {
      return await _localAuth.authenticate(
        localizedReason: reason,
        options: const AuthenticationOptions(
          stickyAuth: true,
          biometricOnly: false,
          useErrorDialogs: true,
        ),
      );
    } catch (e) {
      return false;
    }
  }

  Future<bool> _performIntegrityCheck() async {
    try {
      // Verify app signature / certificate pinning check
      final signatureValid = await _verifyAppSignature();
      // Check for debugging
      final notDebugged = !_isBeingDebugged();
      // Check for hooking frameworks
      final noHooks = await _checkForHookingFrameworks();

      return signatureValid && notDebugged && noHooks;
    } catch (e) {
      return false;
    }
  }

  Future<bool> _verifyAppSignature() async {
    try {
      const platform = MethodChannel('com.payment.security/integrity');
      final result = await platform.invokeMethod<bool>('verifySignature');
      return result ?? false;
    } catch (e) {
      // In development, return true; in production, return false
      return !kIsRelease;
    }
  }

  static const bool kIsRelease = bool.fromEnvironment('dart.vm.product');

  bool _isBeingDebugged() {
    bool debugMode = false;
    assert(() {
      debugMode = true;
      return true;
    }());
    return debugMode && kIsRelease;
  }

  Future<bool> _checkForHookingFrameworks() async {
    if (Platform.isAndroid) {
      // Check for Frida, Xposed, etc.
      final suspiciousFiles = [
        '/data/local/tmp/frida-server',
        '/proc/self/maps',
      ];
      for (final path in suspiciousFiles) {
        if (path == '/data/local/tmp/frida-server') {
          try {
            final file = File(path);
            if (await file.exists()) return false;
          } catch (_) {}
        }
      }
    }
    return true;
  }

  Future<void> storeSecureData(String key, String value) async {
    final encrypted = _encryptData(value);
    await _secureStorage.write(key: key, value: encrypted);
  }

  Future<String?> readSecureData(String key) async {
    final encrypted = await _secureStorage.read(key: key);
    if (encrypted == null) return null;
    return _decryptData(encrypted);
  }

  Future<void> deleteSecureData(String key) async {
    await _secureStorage.delete(key: key);
  }

  String _encryptData(String data) {
    final key = utf8.encode('payment_module_secure_key_2024!@#');
    final hmacSha256 = Hmac(sha256, key);
    final digest = hmacSha256.convert(utf8.encode(data));
    return '${base64Encode(utf8.encode(data))}.$digest';
  }

  String _decryptData(String encryptedData) {
    final parts = encryptedData.split('.');
    if (parts.length != 2) throw Exception('Invalid encrypted data format');
    return utf8.decode(base64Decode(parts[0]));
  }

  String generateTransactionHash(Map<String, dynamic> transactionData) {
    final sortedKeys = transactionData.keys.toList()..sort();
    final dataString =
        sortedKeys.map((k) => '$k=${transactionData[k]}').join('&');
    final bytes = utf8.encode(dataString);
    return sha256.convert(bytes).toString();
  }
}


