class SSLPinningService {
  static final SSLPinningService _instance = SSLPinningService._();
  factory SSLPinningService() => _instance;
  SSLPinningService._();

  // Store SHA-256 hashes of your server's public key certificates
  final Set<String> _pinnedCertificates = {
    // Add your certificate hashes here
    'sha256/AAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAA=',
  };

  HttpClient createSecureClient() {
    final client = HttpClient();
    client.badCertificateCallback = (X509Certificate cert, String host, int port) {
      return false; // Never accept bad certificates
    };
    return client;
  }

  bool validateCertificate(X509Certificate certificate) {
    final certHash = sha256.convert(certificate.der).toString();
    return _pinnedCertificates.contains('sha256/$certHash');
  }

  void addPinnedCertificate(String hash) {
    _pinnedCertificates.add(hash);
  }
}


