import 'dart:convert';
import 'package:http/http.dart' as http;
import 'package:uuid/uuid.dart';
import '../models/payment_models.dart';
import '../security/device_security_service.dart';

abstract class PaymentGatewayService {
  Future<PaymentResult> processPayment({
    required double amount,
    required String currency,
    required PaymentMethod method,
    Map<String, dynamic>? metadata,
  });

  Future<PaymentResult> refundPayment({
    required String transactionId,
    double? amount,
  });

  Future<PaymentResult> verifyTransaction(String transactionId);
}

class StripePaymentService implements PaymentGatewayService {
  final String _apiBaseUrl;
  final String _publishableKey;
  final DeviceSecurityService _securityService;
  final Uuid _uuid = const Uuid();

  StripePaymentService({
    required String apiBaseUrl,
    required String publishableKey,
    DeviceSecurityService? securityService,
  })  : _apiBaseUrl = apiBaseUrl,
        _publishableKey = publishableKey,
        _securityService = securityService ?? DeviceSecurityService.instance;

  Map<String, String> get _headers => {
        'Content-Type': 'application/json',
        'Authorization': 'Bearer $_publishableKey',
        'X-Idempotency-Key': _uuid.v4(),
        'X-Request-Timestamp': DateTime.now().toIso8601String(),
      };

  @override
  Future<PaymentResult> processPayment({
    required double amount,
    required String currency,
    required PaymentMethod method,
    Map<String, dynamic>? metadata,
  }) async {
    try {
      // Security check before processing
      final securityStatus = await _securityService.performSecurityCheck();
      if (!securityStatus.isSecure) {
        return PaymentResult.failure(
          'Payment blocked: Device security check failed',
        );
      }

      final idempotencyKey = _uuid.v4();
      final transactionHash = _securityService.generateTransactionHash({
        'amount': amount,
        'currency': currency,
        'method': method.name,
        'idempotencyKey': idempotencyKey,
        'timestamp': DateTime.now().millisecondsSinceEpoch,
      });

      final response = await http.post(
        Uri.parse('$_apiBaseUrl/create-payment-intent'),
        headers: {
          ..._headers,
          'X-Idempotency-Key': idempotencyKey,
          'X-Transaction-Hash': transactionHash,
        },
        body: jsonEncode({
          'amount': (amount * 100).round(), // Convert to cents
          'currency': currency.toLowerCase(),
          'payment_method_type': _mapPaymentMethod(method),
          'metadata': {
            ...?metadata,
            'device_security_check': securityStatus.isSecure,
            'transaction_hash': transactionHash,
          },
        }),
      );

      if (response.statusCode == 200) {
        final data = jsonDecode(response.body) as Map<String, dynamic>;
        return PaymentResult(
          success: true,
          transactionId: data['payment_intent_id'] as String?,
          status: TransactionStatus.processing,
          amount: amount,
          currency: currency,
          metadata: data,
        );
      } else {
        final error = jsonDecode(response.body);
        return PaymentResult.failure(
          error['message'] as String? ?? 'Payment processing failed',
        );
      }
    } catch (e) {
      return PaymentResult.failure('Payment error: ${e.toString()}');
    }
  }

  @override
  Future<PaymentResult> refundPayment({
    required String transactionId,
    double? amount,
  }) async {
    try {
      final authenticated = await _securityService.authenticateUser(
        'Authenticate to process refund',
      );
      if (!authenticated) {
        return PaymentResult.failure('Authentication required for refund');
      }

      final response = await http.post(
        Uri.parse('$_apiBaseUrl/refund'),
        headers: _headers,
        body: jsonEncode({
          'payment_intent_id': transactionId,
          if (amount != null) 'amount': (amount * 100).round(),
        }),
      );

      if (response.statusCode == 200) {
        final data = jsonDecode(response.body) as Map<String, dynamic>;
        return PaymentResult(
          success: true,
          transactionId: data['refund_id'] as String?,
          status: TransactionStatus.refunded,
          amount: amount ?? 0,
          metadata: data,
        );
      } else {
        return PaymentResult.failure('Refund processing failed');
      }
    } catch (e) {
      return PaymentResult.failure('Refund error: ${e.toString()}');
    }
  }

  @override
  Future<PaymentResult> verifyTransaction(String transactionId) async {
    try {
      final response = await http.get(
        Uri.parse('$_apiBaseUrl/verify/$transactionId'),
        headers: _headers,
      );

      if (response.statusCode == 200) {
        final data = jsonDecode(response.body) as Map<String, dynamic>;
        final status = _mapTransactionStatus(data['status'] as String);
        return PaymentResult(
          success: status == TransactionStatus.completed,
          transactionId: transactionId,
          status: status,
          amount: ((data['amount'] as num?) ?? 0).toDouble() / 100,
          currency: data['currency'] as String? ?? 'USD',
          metadata: data,
        );
      } else {
        return PaymentResult.failure('Transaction verification failed');
      }
    } catch (e) {
      return PaymentResult.failure('Verification error: ${e.toString()}');
    }
  }

  String _mapPaymentMethod(PaymentMethod method) {
    switch (method) {
      case PaymentMethod.applePay:
        return 'apple_pay';
      case PaymentMethod.googlePay:
        return 'google_pay';
      case PaymentMethod.creditCard:
        return 'card';
      case PaymentMethod.inAppPurchase:
        return 'card';
    }
  }

  TransactionStatus _mapTransactionStatus(String status) {
    switch (status) {
      case 'succeeded':
        return TransactionStatus.completed;
      case 'processing':
        return TransactionStatus.processing;
      case 'requires_payment_method':
      case 'requires_confirmation':
        return TransactionStatus.pending;
      case 'canceled':
        return TransactionStatus.cancelled;
      default:
        return TransactionStatus.failed;
    }
  }
}


