import 'dart:async';
import 'dart:io';
import 'package:flutter/foundation.dart';
import 'package:in_app_purchase/in_app_purchase.dart';
import 'package:in_app_purchase_storekit/in_app_purchase_storekit.dart';
import 'package:in_app_purchase_android/in_app_purchase_android.dart';
import 'package:http/http.dart' as http;
import 'dart:convert';
import '../models/payment_models.dart';
import '../security/device_security_service.dart';

class InAppPurchaseService {
  static InAppPurchaseService? _instance;
  final InAppPurchase _iap = InAppPurchase.instance;
  final DeviceSecurityService _securityService;
  final String _verificationServerUrl;

  StreamSubscription<List<PurchaseDetails>>? _subscription;
  final StreamController<PaymentResult> _paymentResultController =
      StreamController<PaymentResult>.broadcast();

  List<ProductDetails> _products = [];
  final Map<String, PurchaseDetails> _pendingPurchases = {};

  Stream<PaymentResult> get paymentResults => _paymentResultController.stream;
  List<ProductDetails> get products => List.unmodifiable(_products);

  InAppPurchaseService._({
    required String verificationServerUrl,
    DeviceSecurityService? securityService,
  })  : _verificationServerUrl = verificationServerUrl,
        _securityService = securityService ?? DeviceSecurityService.instance;

  static InAppPurchaseService initialize({
    required String verificationServerUrl,
    DeviceSecurityService? securityService,
  }) {
    _instance ??= InAppPurchaseService._(
      verificationServerUrl: verificationServerUrl,
      securityService: securityService,
    );
    return _instance!;
  }

  static InAppPurchaseService get instance {
    if (_instance == null) {
      throw StateError('InAppPurchaseService not initialized. Call initialize() first.');
    }
    return _instance!;
  }

  Future<bool> setup() async {
    final available = await _iap.isAvailable();
    if (!available) return false;

    _subscription = _iap.purchaseStream.listen(
      _handlePurchaseUpdates,
      onDone: () => _subscription?.cancel(),
      onError: (error) {
        _paymentResultController.add(
          PaymentResult.failure('Purchase stream error: $error'),
        );
      },
    );

    // Enable pending purchases on Android
    if (Platform.isAndroid) {
      final androidPlatform =
          _iap.getPlatformAddition<InAppPurchaseAndroidPlatformAddition>();
      await androidPlatform.enablePendingPurchases();
    }

    return true;
  }

  Future<List<ProductDetails>> loadProducts(Set<String> productIds) async {
    final response = await _iap.queryProductDetails(productIds);

    if (response.notFoundIDs.isNotEmpty) {
      debugPrint('Products not found: ${response.notFoundIDs}');
    }

    _products = response.productDetails;
    return _products;
  }

  Future<PaymentResult> purchaseProduct(ProductDetails product) async {
    try {
      // Security check
      final securityStatus = await _securityService.performSecurityCheck();
      if (!securityStatus.isSecure) {
        return PaymentResult.failure(
          'Purchase blocked: Device security check failed',
        );
      }

      final purchaseParam = PurchaseParam(productDetails: product);
      final success = await _iap.buyNonConsumable(purchaseParam: purchaseParam);

      if (!success) {
        return PaymentResult.failure('Failed to initiate purchase');
      }

      return PaymentResult(
        success: true,
        status: TransactionStatus.pending,
        amount: _parsePrice(product.rawPrice),
        currency: product.currencyCode,
        metadata: {'productId': product.id},
      );
    } catch (e) {
      return PaymentResult.failure('Purchase error: ${e.toString()}');
    }
  }

  Future<PaymentResult> purchaseSubscription(ProductDetails product) async {
    try {
      final securityStatus = await _securityService.performSecurityCheck();
      if (!securityStatus.isSecure) {
        return PaymentResult.failure(
          'Subscription blocked: Device security check failed',
        );
      }

      final purchaseParam = PurchaseParam(productDetails: product);
      final success = await _iap.buyNonConsumable(purchaseParam: purchaseParam);

      if (!success) {
        return PaymentResult.failure('Failed to initiate subscription');
      }

      return PaymentResult(
        success: true,
        status: TransactionStatus.pending,
        amount: _parsePrice(product.rawPrice),
        currency: product.currencyCode,
        metadata: {
          'productId': product.id,
          'isSubscription': true,
        },
      );
    } catch (e) {
      return PaymentResult.failure('Subscription error: ${e.toString()}');
    }
  }

  Future<PaymentResult> purchaseConsumable(ProductDetails product) async {
    try {
      final securityStatus = await _securityService.performSecurityCheck();
      if (!securityStatus.isSecure) {
        return PaymentResult.failure(
          'Purchase blocked: Device security check failed',
        );
      }

      final purchaseParam = PurchaseParam(productDetails: product);
      final success = await _iap.buyConsumable(purchaseParam: purchaseParam);

      if (!success) {
        return PaymentResult.failure('Failed to initiate consumable purchase');
      }

      return PaymentResult(
        success: true,
        status: TransactionStatus.pending,
        amount: _parsePrice(product.rawPrice),
        currency: product.currencyCode,
        metadata: {'productId': product.id, 'isConsumable': true},
      );
    } catch (e) {
      return PaymentResult.failure('Consumable purchase error: ${e.toString()}');
    }
  }

  Future<void> restorePurchases() async {
    await _iap.restorePurchases();
  }

  void _handlePurchaseUpdates(List<PurchaseDetails> purchases) {
    for (final purchase in purchases) {
      switch (purchase.status) {
        case PurchaseStatus.pending:
          _pendingPurchases[purchase.productID] = purchase;
          _paymentResultController.add(PaymentResult(
            success: false,
            status: TransactionStatus.pending,
            amount: 0,
            metadata: {'productId': purchase.productID},
          ));
          break;

        case PurchaseStatus.purchased:
        case PurchaseStatus.restored:
          _verifyAndCompletePurchase(purchase);
          break;

        case PurchaseStatus.error:
          _pendingPurchases.remove(purchase.productID);
          _paymentResultController.add(PaymentResult.failure(
            purchase.error?.message ?? 'Purchase failed',
          ));
          if (purchase.pendingCompletePurchase) {
            _iap.completePurchase(purchase);
          }
          break;

        case PurchaseStatus.canceled:
          _pendingPurchases.remove(purchase.productID);
          _paymentResultController.add(PaymentResult(
            success: false,
            status: TransactionStatus.cancelled,
            amount: 0,
            metadata: {'productId': purchase.productID},
          ));
          if (purchase.pendingCompletePurchase) {
            _iap.completePurchase(purchase);
          }
          break;
      }
    }
  }

  Future<void> _verifyAndCompletePurchase(PurchaseDetails purchase) async {
    try {
      final verified = await _verifyPurchaseOnServer(purchase);

      if (verified) {
        _pendingPurchases.remove(purchase.productID);
        _paymentResultController.add(PaymentResult(
          success: true,
          transactionId: purchase.purchaseID,
          status: purchase.status == PurchaseStatus.restored
              ? TransactionStatus.completed
              : TransactionStatus.completed,
          amount: 0, // Amount comes from product details
          metadata: {
            'productId': purchase.productID,
            'purchaseId': purchase.purchaseID,
            'verificationData': purchase.verificationData.serverVerificationData,
            'restored': purchase.status == PurchaseStatus.restored,
          },
        ));
      } else {
        _paymentResultController.add(PaymentResult.failure(
          'Purchase verification failed - potential fraud detected',
        ));
      }

      if (purchase.pendingCompletePurchase) {
        await _iap.completePurchase(purchase);
      }
    } catch (e) {
      _paymentResultController.add(PaymentResult.failure(
        'Purchase verification error: ${e.toString()}',
      ));
    }
  }

  Future<bool> _verifyPurchaseOnServer(PurchaseDetails purchase) async {
    try {
      final response = await http.post(
        Uri.parse('$_verificationServerUrl/verify-purchase'),
        headers: {'Content-Type': 'application/json'},
        body: jsonEncode({
          'platform': Platform.isIOS ? 'ios' : 'android',
          'productId': purchase.productID,
          'purchaseId': purchase.purchaseID,
          'verificationData': purchase.verificationData.serverVerificationData,
          'source': purchase.verificationData.source,
          'transactionDate': purchase.transactionDate,
        }),
      );

      if (response.statusCode == 200) {
        final data = jsonDecode(response.body) as Map<String, dynamic>;
        return data['verified'] == true;
      }
      return false;
    } catch (e) {
      debugPrint('Server verification error: $e');
      return false;
    }
  }

  double _parsePrice(double rawPrice) {
    return rawPrice;
  }

  Future<void> dispose() async {
    await _subscription?.cancel();
    await _paymentResultController.close();
  }
}


// lib/payment_module/services/mobile_wallet_service.dart

import 'dart:io';
import 'package:pay/pay.dart';
import '../models/payment_models.dart';
import '../security/device_security_service.dart';
import 'payment_gateway_service.dart';

class MobileWalletService {
  final PaymentGatewayService _gatewayService;
  final DeviceSecurityService _securityService;

  static const _defaultApplePayConfig = PaymentConfiguration.fromJsonString('''
  {
    "provider": "apple_pay",
    "data": {
      "merchantIdentifier": "merchant.com.yourapp.pay",
      "displayName": "Your App",
      "merchantCapabilities": ["3DS", "debit", "credit"],
      "supportedNetworks": ["amex", "visa", "discover", "masterCard"],
      "countryCode": "US",
      "currencyCode": "USD"
    }
  }
  ''');

  static const _defaultGooglePayConfig = PaymentConfiguration.fromJsonString('''
  {
    "provider": "google_pay",
    "data": {
      "environment": "PRODUCTION",
      "apiVersion": 2,
      "apiVersionMinor": 0,
      "allowedPaymentMethods": [{
        "type": "CARD",
        "parameters": {
          "allowedAuthMethods": ["PAN_ONLY", "CRYPTOGRAM_3DS"],
          "allowedCardNetworks": ["AMEX", "DISCOVER", "MASTERCARD", "VISA"]
        },
        "tokenizationSpecification": {
          "type": "PAYMENT_GATEWAY",
          "parameters": {
            "gateway": "stripe",
            "stripe:version": "2023-10-16",
            "stripe:publishableKey": "pk_live_your_key"
          }
        }
      }],
      "merchantInfo": {
        "merchantId": "BCR2DN4T6XXXXX",
        "merchantName": "Your App"
      },
      "transactionInfo": {
        "totalPriceStatus": "FINAL",
        "countryCode": "US",
        "currencyCode": "USD"
      }
    }
  }
  ''');

  MobileWalletService({
    required PaymentGatewayService gatewayService,
    DeviceSecurityService? securityService,
  })  : _gatewayService = gatewayService,
        _securityService = securityService ?? DeviceSecurityService.instance;

  Future<bool> isApplePayAvailable() async {
    if (!Platform.isIOS) return false;
    try {
      final pay = Pay({PayProvider.apple_pay: _defaultApplePayConfig});
      return await pay.userCanPay(PayProvider.apple_pay);
    } catch (e) {
      return false;
    }
  }

  Future<bool> isGooglePayAvailable() async {
    if (!Platform.isAndroid) return false;
    try {
      final pay = Pay({PayProvider.google_pay: _defaultGooglePayConfig});
      return await pay.userCanPay(PayProvider.google_pay);
    } catch (e) {
      return false;
    }
  }

  Future<PaymentResult> processApplePay({
    required double amount,
    required String currency,
    required List<PaymentItem> items,
    Map<String, dynamic>? metadata,
  }) async {
    try {
      final securityStatus = await _securityService.performSecurityCheck();
      if (!securityStatus.isSecure) {
        return PaymentResult.failure('Payment blocked: Insecure device');
      }

      // Apple Pay processes through the native sheet
      // The token is then sent to your payment gateway
      return await _gatewayService.processPayment(
        amount: amount,
        currency: currency,
        method: PaymentMethod.applePay,
        metadata: {
          ...?metadata,
          'wallet_type': 'apple_pay',
          'items': items.map((i) => {'label': i.label, 'amount': i.amount}).toList(),
        },
      );
    } catch (e) {
      return PaymentResult.failure('Apple Pay error: ${e.toString()}');
    }
  }

  Future<PaymentResult> processGooglePay({
    required double amount,
    required String currency,
    required List<PaymentItem> items,
    Map<String, dynamic>? metadata,
  }) async {
    try {
      final securityStatus = await _securityService.performSecurityCheck();
      if (!securityStatus.isSecure) {
        return PaymentResult.failure('Payment blocked: Insecure device');
      }

      return await _gatewayService.processPayment(
        amount: amount,
        currency: currency,
        method: PaymentMethod.googlePay,
        metadata: {
          ...?metadata,
          'wallet_type': 'google_pay',
          'items': items.map((i) => {'label': i.label, 'amount': i.amount}).toList(),
        },
      );
    } catch (e) {
      return PaymentResult.failure('Google Pay error: ${e.toString()}');
    }
  }

  PaymentConfiguration getApplePayConfig() => _defaultApplePayConfig;
  PaymentConfiguration getGooglePayConfig() => _defaultGooglePayConfig;
}


// lib/payment_module/services/transaction_logger.dart

import 'dart:convert';
import 'package:flutter/foundation.dart';
import 'package:flutter_secure_storage/flutter_secure_storage.dart';
import '../models/payment_models.dart';

class TransactionLogger {
  static final TransactionLogger _instance = TransactionLogger._();
  factory TransactionLogger() => _instance;
  TransactionLogger._();

  final FlutterSecureStorage _storage = const FlutterSecureStorage();
  static const String _logKey = 'transaction_log';
  static const int _maxLogEntries = 500;

  Future<void> logTransaction(PaymentResult result) async {
    try {
      final logs = await _getExistingLogs();
      logs.add({
        ...result.toJson(),
        'loggedAt': DateTime.now().toIso8601String(),
      });

      // Keep only the last N entries
      if (logs.length > _maxLogEntries) {
        logs.removeRange(0, logs.length - _maxLogEntries);
      }

      await _storage.write(key: _logKey, value: jsonEncode(logs));
    } catch (e) {
      debugPrint('Failed to log transaction: $e');
    }
  }

  Future<List<Map<String, dynamic>>> getTransactionHistory({
    int? limit,
    TransactionStatus? filterStatus,
  }) async {
    try {
      var logs = await _getExistingLogs();

      if (filterStatus != null) {
        logs = logs
            .where((log) => log['status'] == filterStatus.name)
            .toList();
      }

      if (limit != null && logs.length > limit) {
        logs = logs.sublist(logs.length - limit);
      }

      return logs;
    } catch (e) {
      debugPrint('Failed to get transaction history: $e');
      return [];
    }
  }

  Future<void> clearHistory() async {
    await _storage.delete(key: _logKey);
  }

  Future<List<Map<String, dynamic>>> _getExistingLogs() async {
    final existing = await _storage.read(key: _logKey);
    if (existing == null) return [];
    return (jsonDecode(existing) as List)
        .cast<Map<String, dynamic>>();
  }
}


// lib/payment_module/payment_module.dart

import 'dart:async';
import 'package:flutter/foundation.dart';
import 'models/payment_models.dart';
import 'security/device_security_service.dart';
import 'services/payment_gateway_service.dart';
import 'services/in_app_purchase_service.dart';
import 'services/mobile_wallet_service.dart';
import 'services/transaction_logger.dart';

class PaymentModule {
  static PaymentModule? _instance;

  final PaymentGatewayService _gatewayService;
  final InAppPurchaseService _iapService;
  final MobileWalletService _walletService;
  final DeviceSecurityService _securityService;
  final TransactionLogger _transactionLogger;

  bool _initialized = false;
  DeviceSecurityStatus? _lastSecurityCheck;

  PaymentModule._({
    required PaymentGatewayService gatewayService,
    required InAppPurchaseService iapService,
    required MobileWalletService walletService,
    DeviceSecurityService? securityService,
    TransactionLogger? transactionLogger,
  })  : _gatewayService = gatewayService,
        _iapService = iapService,
        _walletService = walletService,
        _securityService = securityService ?? DeviceSecurityService.instance,
        _transactionLogger = transactionLogger ?? TransactionLogger();

  static PaymentModule initialize({
    required String stripeApiUrl,
    required String stripePublishableKey,
    required String purchaseVerificationUrl,
    required Set<String> productIds,
  }) {
    if (_instance != null) return _instance!;

    final gatewayService = StripePaymentService(
      apiBaseUrl: stripeApiUrl,
      publishableKey: stripePublishableKey,
    );

    final iapService = InAppPurchaseService.initialize(
      verificationServerUrl: purchaseVerificationUrl,
    );

    final walletService = MobileWalletService(
      gatewayService: gatewayService,
    );

    _instance = PaymentModule._(
      gatewayService: gatewayService,
      iapService: iapService,
      walletService: walletService,
    );

    // Setup IAP and load products
    _instance!._setup(productIds);

    return _instance!;
  }

  static PaymentModule get instance {
    if (_instance == null) {
      throw StateError('PaymentModule not initialized. Call initialize() first.');
    }
    return _instance!;
  }

  Future<void> _setup(Set<String> productIds) async {
    if (_initialized) return;

    // Perform initial security check
    _lastSecurityCheck = await _securityService.performSecurityCheck();

    if (!_lastSecurityCheck!.isSecure) {
      debugPrint('WARNING: Device security check failed during initialization');
    }

    // Setup IAP
    final iapAvailable = await _iapService.setup();
    if (iapAvailable) {
      await _iapService.loadProducts(productIds);
    }

    // Listen to IAP results
    _iapService.paymentResults.listen((result) {
      _transactionLogger.logTransaction(result);
    });

    _initialized = true;
  }

  // ==================== Security ====================

  Future<DeviceSecurityStatus> checkDeviceSecurity() async {
    _lastSecurityCheck = await _securityService.performSecurityCheck();
    return _lastSecurityCheck!;
  }

  DeviceSecurityStatus? get lastSecurityCheck => _lastSecurityCheck;

  Future<bool> authenticateForPayment() async {
    return await _securityService.authenticateUser(
      'Authenticate to proceed with payment',
    );
  }

  // ==================== Card Payments ====================

  Future<PaymentResult> processCardPayment({
    required double amount,
    String currency = 'USD',
    Map<String, dynamic>? metadata,
  }) async {
    return _executeSecurePayment(() => _gatewayService.processPayment(
          amount: amount,
          currency: currency,
          method: PaymentMethod.creditCard,
          metadata: metadata,
        ));
  }

  // ==================== Mobile Wallet ====================

  Future<bool> get isApplePayAvailable => _walletService.isApplePayAvailable();
  Future<bool> get isGooglePayAvailable => _walletService.isGooglePayAvailable();

  Future<PaymentResult> processApplePay({
    required double amount,
    required String currency,
    required String itemLabel,
    Map<String, dynamic>? metadata,
  }) async {
    return _executeSecurePayment(() => _walletService.processApplePay(
          amount: amount,
          currency: currency,
          items: [PaymentItem(label: itemLabel, amount: amount.toStringAsFixed(2))],
          metadata: metadata,
        ));
  }

  Future<PaymentResult> processGooglePay({
    required double amount,
    required String currency,
    required String itemLabel,
    Map<String, dynamic>? metadata,
  }) async {
    return _executeSecurePayment(() => _walletService.processGooglePay(
          amount: amount,
          currency: currency,
          items: [PaymentItem(label: itemLabel, amount: amount.toStringAsFixed(2))],
          metadata: metadata,
        ));
  }

  // ==================== In-App Purchases ====================

  Stream<PaymentResult> get purchaseStream => _iapService.paymentResults;

  Future<PaymentResult> purchaseProduct(String productId) async {
    final product = _iapService.products.firstWhere(
      (p) => p.id == productId,
      orElse: () => throw Exception('Product not found: $productId'),
    );
    return _executeSecurePayment(() => _iapService.purchaseProduct(product));
  }

  Future<PaymentResult> purchaseSubscription(String productId) async {
    final product = _iapService.products.firstWhere(
      (p) => p.id == productId,
      orElse: () => throw Exception('Subscription not found: $productId'),
    );
    return _executeSecurePayment(
        () => _iapService.purchaseSubscription(product));
  }

  Future<PaymentResult> purchaseConsumable(String productId) async {
    final product = _iapService.products.firstWhere(
      (p) => p.id == productId,
      orElse: () => throw Exception('Consumable not found: $productId'),
    );
    return _executeSecurePayment(
        () => _iapService.purchaseConsumable(product));
  }

  Future<void> restorePurchases() => _iapService.restorePurchases();

  // ==================== Refunds ====================

  Future<PaymentResult> refundPayment({
    required String transactionId,
    double? amount,
  }) async {
    return _executeSecurePayment(() => _gatewayService.refundPayment(
          transactionId: transactionId,
          amount: amount,
        ));
  }

  // ==================== Transaction History ====================

  Future<PaymentResult> verifyTransaction(String transactionId) =>
      _gatewayService.verifyTransaction(transactionId);

  Future<List<Map<String, dynamic>>> getTransactionHistory({
    int? limit,
    TransactionStatus? filterStatus,
  }) =>
      _transactionLogger.getTransactionHistory(
        limit: limit,
        filterStatus: filterStatus,
      );

  // ==================== Internal ====================

  Future<PaymentResult> _executeSecurePayment(
    Future<PaymentResult> Function() paymentAction,
  ) async {
    try {
      // Re-check security if last check is stale (> 5 minutes)
      if (_lastSecurityCheck == null ||
          DateTime.now().difference(_lastSecurityCheck!.checkedAt).inMinutes > 5) {
        _lastSecurityCheck = await _securityService.performSecurityCheck();
      }

      if (!_lastSecurityCheck!.isSecure) {
        final result = PaymentResult.failure(
          'Payment blocked: Device integrity check failed. '
          'Rooted: ${_lastSecurityCheck!.isRooted}, '
          'Emulator: ${_lastSecurityCheck!.isEmulator}',
        );
        await _transactionLogger.logTransaction(result);
        return result;
      }

      final result = await paymentAction();
      await _transactionLogger.logTransaction(result);
      return result;
    } catch (e) {
      final result = PaymentResult.failure('Payment execution error: $e');
      await _transactionLogger.logTransaction(result);
      return result;
    }
  }

  Future<void> dispose() async {
    await _iapService.dispose();
    _instance = null;
    _initialized = false;
  }
}


// lib/payment_module/providers/payment_provider.dart

import 'dart:async';
import 'package:flutter/foundation.dart';
import '../models/payment_models.dart';
import '../payment_module.dart';

class PaymentProvider extends ChangeNotifier {
  final PaymentModule _paymentModule;

  PaymentResult? _lastResult;
  bool _isProcessing = false;
  DeviceSecurityStatus? _securityStatus;
  String? _errorMessage;
  List<Map<String, dynamic>> _transactionHistory = [];
  StreamSubscription<PaymentResult>? _purchaseSubscription;

  PaymentProvider({PaymentModule? paymentModule})
      : _paymentModule = paymentModule ?? PaymentModule.instance {
    _init();
  }

  PaymentResult? get lastResult => _lastResult;
  bool get isProcessing => _isProcessing;
  DeviceSecurityStatus? get securityStatus => _securityStatus;
  String? get errorMessage => _errorMessage;
  List<Map<String, dynamic>> get transactionHistory => _transactionHistory;
  bool get isDeviceSecure => _securityStatus?.isSecure ?? false;

  void _init() {
    _purchaseSubscription = _paymentModule.purchaseStream.listen((result) {
      _lastResult = result;
      _isProcessing = false;
      notifyListeners();
    });
  }

  Future<void> checkSecurity() async {
    _securityStatus = await _paymentModule.checkDeviceSecurity();
    notifyListeners();
  }

  Future<PaymentResult> processCardPayment({
    required double amount,
    String currency = 'USD',
  }) async {
    return _processPayment(() => _paymentModule.processCardPayment(
          amount: amount,
          currency: currency,
        ));
  }

  Future<PaymentResult> processApplePay({
    required double amount,
    required String currency,
    required String itemLabel,
  }) async {
    return _processPayment(() => _paymentModule.processApplePay(
          amount: amount,
          currency: currency,
          itemLabel: itemLabel,
        ));
  }

  Future<PaymentResult> processGooglePay({
    required double amount,
    required String currency,
    required String itemLabel,
  }) async {
    return _processPayment(() => _paymentModule.processGooglePay(
          amount: amount,
          currency: currency,
          itemLabel: itemLabel,
        ));
  }

  Future<PaymentResult> purchaseProduct(String productId) async {
    return _processPayment(() => _paymentModule.purchaseProduct(productId));
  }

  Future<PaymentResult> purchaseSubscription(String productId) async {
    return _processPayment(
        () => _paymentModule.purchaseSubscription(productId));
  }

  Future<PaymentResult> refund({
    required String transactionId,
    double? amount,
  }) async {
    return _processPayment(() => _paymentModule.refundPayment(
          transactionId: transactionId,
          amount: amount,
        ));
  }

  Future<void> restorePurchases() async {
    _isProcessing = true;
    _errorMessage = null;
    notifyListeners();

    try {
      await _paymentModule.restorePurchases();
    } catch (e) {
      _errorMessage = e.toString();
    } finally {
      _isProcessing = false;
      notifyListeners();
    }
  }

  Future<void> loadTransactionHistory({int? limit}) async {
    _transactionHistory = await _paymentModule.getTransactionHistory(
      limit: limit,
    );
    notifyListeners();
  }

  Future<PaymentResult> _processPayment(
    Future<PaymentResult> Function() action,
  ) async {
    _isProcessing = true;
    _errorMessage = null;
    notifyListeners();

    try {
      _lastResult = await action();
      if (!_lastResult!.success) {
        _errorMessage = _lastResult!.errorMessage;
      }
    } catch (e) {
      _lastResult = PaymentResult.failure(e.toString());
      _errorMessage = e.toString();
    } finally {
      _isProcessing = false;
      notifyListeners();
    }

    return _lastResult!;
  }

  @override
  void dispose() {
    _purchaseSubscription?.cancel();
    super.dispose();
  }
}


// lib/payment_module/widgets/payment_button.dart

import 'dart:io';
import 'package:flutter/material.dart';
import 'package:pay/pay.dart' as pay;
import '../models/payment_models.dart';
import '../providers/payment_provider.dart';

class SecurePaymentButton extends StatelessWidget {
  final PaymentMethod method;
  final double amount;
  final String currency;
  final String label;
  final VoidCallback? onPressed;
  final Function(PaymentResult)? onResult;
  final PaymentProvider provider;

  const SecurePaymentButton({
    super.key,
    required this.method,
    required this.amount,
    required this.currency,
    required this.label,
    required this.provider,
    this.onPressed,
    this.onResult,
  });

  @override
  Widget build(BuildContext context) {
    return ListenableBuilder(
      listenable: provider,
      builder: (context, _) {
        if (provider.isProcessing) {
          return const SizedBox(
            height: 48,
            child: Center(child: CircularProgressIndicator()),
          );
        }

        switch (method) {
          case PaymentMethod.applePay:
            if (!Platform.isIOS) return const SizedBox.shrink();
            return _buildApplePayButton(context);
          case PaymentMethod.googlePay:
            if (!Platform.isAndroid) return const SizedBox.shrink();
            return _buildGooglePayButton(context);
          case PaymentMethod.creditCard:
            return _buildCardPayButton(context);
          case PaymentMethod.inAppPurchase:
            return _buildIAPButton(context);
        }
      },
    );
  }

  Widget _buildApplePayButton(BuildContext context) {
    return SizedBox(
      width: double.infinity,
      height: 48,
      child: ElevatedButton.icon(
        onPressed: () => _handlePayment(context, PaymentMethod.applePay),
        icon: const Icon(Icons.apple),
        label: Text('Pay with Apple Pay - ${_formatAmount()}'),
        style: ElevatedButton.styleFrom(
          backgroundColor: Colors.black,
          foregroundColor: Colors.white,
          shape: RoundedRectangleBorder(
            borderRadius: BorderRadius.circular(8),
          ),
        ),
      ),
    );
  }

  Widget _buildGooglePayButton(BuildContext context) {
    return SizedBox(
      width: double.infinity,
      height: 48,
      child: ElevatedButton.icon(
        onPressed: () => _handlePayment(context, PaymentMethod.googlePay),
        icon: const Icon(Icons.g_mobiledata),
        label: Text('Pay with Google Pay - ${_formatAmount()}'),
        style: ElevatedButton.styleFrom(
          backgroundColor: Colors.white,
          foregroundColor: Colors.black,
          shape: RoundedRectangleBorder(
            borderRadius: BorderRadius.circular(8),
            side: const BorderSide(color: Colors.grey),
          ),
        ),
      ),
    );
  }

  Widget _buildCardPayButton(BuildContext context) {
    return SizedBox(
      width: double.infinity,
      height: 48,
      child: ElevatedButton.icon(
        onPressed: () => _handlePayment(context, PaymentMethod.creditCard),
        icon: const Icon(Icons.credit_card),
        label: Text('Pay ${_formatAmount()}'),
        style: ElevatedButton.styleFrom(
          backgroundColor: Theme.of(context).primaryColor,
          foregroundColor: Colors.white,
          shape: RoundedRectangleBorder(
            borderRadius: BorderRadius.circular(8),
          ),
        ),
      ),
    );
  }

  Widget _buildIAPButton(BuildContext context) {
    return SizedBox(
      width: double.infinity,
      height: 48,
      child: ElevatedButton(
        onPressed: () => _handlePayment(context, PaymentMethod.inAppPurchase),
        style: ElevatedButton.styleFrom(
          backgroundColor: Colors.blue,
          foregroundColor: Colors.white,
          shape: RoundedRectangleBorder(
            borderRadius: BorderRadius.circular(8),
          ),
        ),
        child: Text(label),
      ),
    );
  }

  Future<void> _handlePayment(BuildContext context, PaymentMethod method) async {
    onPressed?.call();

    PaymentResult result;
    switch (method) {
      case PaymentMethod.applePay:
        result = await provider.processApplePay(
          amount: amount,
          currency: currency,
          itemLabel: label,
        );
        break;
      case PaymentMethod.googlePay:
        result = await provider.processGooglePay(
          amount: amount,
          currency: currency,
          itemLabel: label,
        );
        break;
      case PaymentMethod.creditCard:
        result = await provider.processCardPayment(
          amount: amount,
          currency: currency,
        );
        break;
      case PaymentMethod.inAppPurchase:
        result = await provider.purchaseProduct(label);
        break;
    }

    onResult?.call(result);
  }

  String _formatAmount() {
    return '$currency ${amount.toStringAsFixed(2)}';
  }
}


// lib/payment_module/widgets/payment_sheet.dart

import 'dart:io';
import 'package:flutter/material.dart';
import 'package:provider/provider.dart';
import '../models/payment_models.dart';
import '../providers/payment_provider.dart';
import 'payment_button.dart';

class PaymentSheet extends StatefulWidget {
  final double amount;
  final String currency;
  final String itemName;
  final String? itemDescription;
  final Function(PaymentResult)? onPaymentComplete;
  final List<PaymentMethod> availableMethods;

  const PaymentSheet({
    super.key,
    required this.amount,
    this.currency = 'USD',
    required this.itemName,
    this.itemDescription,
    this.onPaymentComplete,
    this.availableMethods = const [
      PaymentMethod.creditCard,
      PaymentMethod.applePay,
      PaymentMethod.googlePay,
    ],
  });

  static Future<PaymentResult?> show(
    BuildContext context, {
    required double amount,
    String currency = 'USD',
    required String itemName,
    String? itemDescription,
    List<PaymentMethod>? availableMethods,
  }) async {
    return showModalBottomSheet<PaymentResult>(
      context: context,
      isScrollControlled: true,
      backgroundColor: Colors.transparent,
      builder: (context) => PaymentSheet(
        amount: amount,
        currency: currency,
        itemName: itemName,
        itemDescription: itemDescription,
        availableMethods: availableMethods ??
            [
              PaymentMethod.creditCard,
              if (Platform.isIOS) PaymentMethod.applePay,
              if (Platform.isAndroid) PaymentMethod.googlePay,
            ],
      ),
    );
  }

  @override
  State<PaymentSheet> createState() => _PaymentSheetState();
}

class _PaymentSheetState extends State<PaymentSheet> {
  late PaymentProvider _provider;
  bool _securityChecked = false;

  @override
  void initState() {
    super.initState();
    _provider = PaymentProvider();
    _performSecurityCheck();
  }

  Future<void> _performSecurityCheck() async {
    await _provider.checkSecurity();
    setState(() => _securityChecked = true);
  }

  @override
  void dispose() {
    _provider.dispose();
    super.dispose();
  }

  @override
  Widget build(BuildContext context) {
    return ChangeNotifierProvider.value(
      value: _provider,
      child: Container(
        decoration: const BoxDecoration(
          color: Colors.white,
          borderRadius: BorderRadius.vertical(top: Radius.circular(20)),
        ),
        padding: const EdgeInsets.all(24),
        child: SafeArea(
          child: Column(
            mainAxisSize: MainAxisSize.min,
            crossAxisAlignment: CrossAxisAlignment.stretch,
            children: [
              _buildHandle(),
              const SizedBox(height: 16),
              _buildHeader(),
              const SizedBox(height: 8),
              if (widget.itemDescription != null) ...[
                Text(
                  widget.itemDescription!,
                  style: Theme.of(context).textTheme.bodyMedium?.copyWith(
                        color: Colors.grey[600],
                      ),
                ),
                const SizedBox(height: 16),
              ],
              _buildAmountDisplay(),
              const SizedBox(height: 24),
              if (!_securityChecked)
                const Center(child: CircularProgressIndicator())
              else if (!_provider.isDeviceSecure)
                _buildSecurityWarning()
              else
                _buildPaymentOptions(),
              if (_provider.errorMessage != null) ...[
                const SizedBox(height: 16),
                _buildErrorMessage(),
              ],
              const SizedBox(height: 16),
              _buildSecurityBadge(),
            ],
          ),
        ),
      ),
    );
  }

  Widget _buildHandle() {
    return Center(
      child: Container(
        width: 40,
