  Widget _buildHeader() {
    return Text(
      widget.itemName,
      style: Theme.of(context).textTheme.headlineSmall?.copyWith(
            fontWeight: FontWeight.bold,
          ),
    );
  }

  Widget _buildAmountDisplay() {
    return Container(
      padding: const EdgeInsets.all(16),
      decoration: BoxDecoration(
        color: Colors.grey[50],
        borderRadius: BorderRadius.circular(12),
        border: Border.all(color: Colors.grey[200]!),
      ),
      child: Row(
        mainAxisAlignment: MainAxisAlignment.spaceBetween,
        children: [
          const Text(
            'Total',
            style: TextStyle(fontSize: 18, fontWeight: FontWeight.w500),
          ),
          Text(
            '${widget.currency} ${widget.amount.toStringAsFixed(2)}',
            style: const TextStyle(
              fontSize: 24,
              fontWeight: FontWeight.bold,
              color: Colors.green,
            ),
          ),
        ],
      ),
    );
  }

  Widget _buildPaymentOptions() {
    return Consumer<PaymentProvider>(
      builder: (context, provider, _) {
        return Column(
          children: widget.availableMethods.map((method) {
            return Padding(
              padding: const EdgeInsets.only(bottom: 12),
              child: SecurePaymentButton(
                method: method,
                amount: widget.amount,
                currency: widget.currency,
                label: widget.itemName,
                provider: provider,
                onResult: (result) {
                  widget.onPaymentComplete?.call(result);
                  if (result.success) {
                    Navigator.of(context).pop(result);
                    _showSuccessDialog(context, result);
                  }
                },
              ),
            );
          }).toList(),
        );
      },
    );
  }

  Widget _buildSecurityWarning() {
    return Container(
      padding: const EdgeInsets.all(16),
      decoration: BoxDecoration(
        color: Colors.red[50],
        borderRadius: BorderRadius.circular(12),
        border: Border.all(color: Colors.red[200]!),
      ),
      child: Column(
        children: [
          const Icon(Icons.security, color: Colors.red, size: 48),
          const SizedBox(height: 8),
          const Text(
            'Security Check Failed',
            style: TextStyle(
              fontWeight: FontWeight.bold,
              color: Colors.red,
              fontSize: 16,
            ),
          ),
          const SizedBox(height: 4),
          Text(
            'Payments are disabled on this device due to security concerns. '
            'Please use a non-rooted/non-jailbroken device.',
            textAlign: TextAlign.center,
            style: TextStyle(color: Colors.red[700], fontSize: 13),
          ),
        ],
      ),
    );
  }

